    if args.action == 'copy':
        shutil.copy2(args.source, args.dest)
        print(f'Kopyalandi: {args.source} -> {args.dest}')
    elif args.action == 'move':
        shutil.move(args.source, args.dest)
        print(f'Tasindi: {args.source} -> {args.dest}')
    elif args.action == 'delete':
        os.remove(args.source)
        print(f'Silindi: {args.source}')
    elif args.action == 'list':
        for f in os.listdir(args.source):
            print(f)

